#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {5, 2, 8, 1, 9, 3};

    // ترتيب تصاعدي — الافتراضي
    std::sort(v.begin(), v.end());
    // v = {1, 2, 3, 5, 8, 9}

    // ترتيب تنازلي بمقارنة lambda
    std::sort(v.begin(), v.end(), [](int a, int b) {
        return a > b;
    });
    // v = {9, 8, 5, 3, 2, 1}

    for (int x : v) std::cout << x << ' ';
    return 0;
}

#include <algorithm>
#include <vector>
#include <string>
#include <iostream>

int main() {
    std::vector<int> v = {10, 25, 30, 45, 50};

    // find: يبحث عن قيمة محددة — O(n)
    auto it = std::find(v.begin(), v.end(), 30);
    if (it != v.end()) {
        std::cout << "وُجد في الموضع: " << (it - v.begin()) << '\n'; // 2
    }

    // find_if: يبحث بشرط مخصص
    auto it2 = std::find_if(v.begin(), v.end(), [](int x) {
        return x > 40;
    });
    if (it2 != v.end()) {
        std::cout << "أول عنصر > 40: " << *it2 << '\n'; // 45
    }

    return 0;
}

#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    // يجب أن يكون النطاق مرتبًا مسبقًا!
    std::vector<int> v = {1, 3, 5, 7, 9, 11, 13};

    // binary_search: يُرجع true/false فقط — O(log n)
    bool exists = std::binary_search(v.begin(), v.end(), 7);
    std::cout << "7 موجودة: " << exists << '\n'; // 1 (true)

    // lower_bound: يُرجع مكرر لأول عنصر >= القيمة
    auto it = std::lower_bound(v.begin(), v.end(), 6);
    // it يشير لـ 7 (أول عنصر >= 6)
    std::cout << "أول عنصر >= 6: " << *it << '\n';

    // استخدام عملي: إدراج مع الحفاظ على الترتيب
    v.insert(it, 6);
    // v = {1, 3, 5, 6, 7, 9, 11, 13}

    for (int x : v) std::cout << x << ' ';
    return 0;
}

#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, -2, 3, -4, 5, -6, 7};

    // count: عدّ القيم المساوية
    int negatives = std::count(v.begin(), v.end(), -2);
    std::cout << "عدد -2: " << negatives << '\n'; // 1

    // count_if: عدّ العناصر التي تحقّق شرطًا
    int neg_count = std::count_if(v.begin(), v.end(), [](int x) {
        return x < 0;
    });
    std::cout << "عدد السالبات: " << neg_count << '\n'; // 3

    return 0;
}

#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 4, 5};

    // تحويل في المكان: ضرب كل عنصر في 2
    std::transform(v.begin(), v.end(), v.begin(), [](int x) {
        return x * 2;
    });
    // v = {2, 4, 6, 8, 10}

    // تحويل إلى حاوية أخرى
    std::vector<int> squares;
    std::transform(v.begin(), v.end(), std::back_inserter(squares), [](int x) {
        return x * x;
    });
    // squares = {4, 16, 36, 64, 100}

    for (int x : squares) std::cout << x << ' ';
    return 0;
}

#include <numeric>
#include <vector>
#include <string>
#include <iostream>

int main() {
    std::vector<int> v = {10, 20, 30, 40};

    // جمع بسيط — القيمة الأولية 0 تحدد نوع النتيجة (int)
    int sum = std::accumulate(v.begin(), v.end(), 0);
    std::cout << "المجموع: " << sum << '\n'; // 100

    // جمع حقول من بنية
    struct Item { std::string name; int price; };
    std::vector<Item> cart = {{"كتاب", 30}, {"قلم", 5}, {"دفتر", 15}};
    int total = std::accumulate(cart.begin(), cart.end(), 0,
        [](int s, const Item& i) { return s + i.price; });
    std::cout << "الإجمالي: " << total << '\n'; // 50

    // ضرب كل العناصر
    int product = std::accumulate(v.begin(), v.end(), 1, std::multiplies<>());
    std::cout << "الجداء: " << product << '\n'; // 240000

    return 0;
}

#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, -2, 3, -4, 5, -6, 7};

    // ❌ remove_if وحده لا يُغيّر الحجم!
    // auto new_end = std::remove_if(v.begin(), v.end(), [](int x) { return x < 0; });
    // v.size() لا تزال 7

    // ✅ النمط الصحيح: erase-remove idiom
    v.erase(
        std::remove_if(v.begin(), v.end(), [](int x) { return x < 0; }),
        v.end()
    );
    // v = {1, 3, 5, 7} — الحجم الآن 4

    for (int x : v) std::cout << x << ' ';
    return 0;
}

#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 4, 5};

    // reverse: عكس الترتيب بالكامل
    std::reverse(v.begin(), v.end());
    // v = {5, 4, 3, 2, 1}

    // rotate: يدور بحيث يصبح العنصر المحدد أولًا
    // هنا العنصر في الموضع 2 (وهو 3) يصبح الأول
    std::rotate(v.begin(), v.begin() + 2, v.end());
    // v = {3, 2, 1, 5, 4}

    for (int x : v) std::cout << x << ' ';
    return 0;
}

#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {2, 4, 6, 8, 10};

    // any_of: هل أي عنصر يحقق الشرط؟ (يتوقف عند الأول)
    bool has_odd = std::any_of(v.begin(), v.end(), [](int x) {
        return x % 2 != 0;
    });
    std::cout << "يوجد فردي: " << has_odd << '\n'; // 0 (false)

    // all_of: هل كل العناصر تُحقق الشرط؟ (يتوقف عند الأول الفاشل)
    bool all_even = std::all_of(v.begin(), v.end(), [](int x) {
        return x % 2 == 0;
    });
    std::cout << "كلها زوجية: " << all_even << '\n'; // 1 (true)

    // none_of: هل لا يوجد عنصر يُحقق الشرط؟
    bool no_negative = std::none_of(v.begin(), v.end(), [](int x) {
        return x < 0;
    });
    std::cout << "لا سالبات: " << no_negative << '\n'; // 1 (true)

    return 0;
}

#include <algorithm>
#include <numeric>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v(5);

    // fill: ملء كل العناصر بقيمة واحدة
    std::fill(v.begin(), v.end(), 42);
    // v = {42, 42, 42, 42, 42}

    // generate: ملء بدالة تُستدعى لكل عنصر
    int counter = 0;
    std::generate(v.begin(), v.end(), [&counter]() { return counter += 10; });
    // v = {10, 20, 30, 40, 50}

    // iota: ملء بقيم متزايدة (0, 1, 2, ...)
    std::iota(v.begin(), v.end(), 100);
    // v = {100, 101, 102, 103, 104}

    for (int x : v) std::cout << x << ' ';
    return 0;
}

#include <algorithm>
#include <vector>
#include <string>
#include <iostream>

int main() {
    std::vector<int> v = {40, 10, 70, 20, 50};

    // تُرجع مكرّر لا قيمة — تحقق من النطاق الفارغ أولًا!
    auto min_it = std::min_element(v.begin(), v.end());
    auto max_it = std::max_element(v.begin(), v.end());
    std::cout << "الأصغر: " << *min_it << " في الموضع " << (min_it - v.begin()) << '\n';
    std::cout << "الأكبر: " << *max_it << '\n';

    // مع مقارنة مخصصة: أقصر نص
    std::vector<std::string> words = {"banana", "apple", "cherry"};
    auto shortest = std::min_element(words.begin(), words.end(),
        [](const std::string& a, const std::string& b) { return a.size() < b.size(); });
    std::cout << "الأقصر: " << *shortest << '\n'; // apple

    return 0;
}

#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {5, 1, 3, 2, 4}; // غير مرتب!

    // ❌ النتيجة غير مضمونة — قد يُرجع true أو false خطأ
    bool wrong = std::binary_search(v.begin(), v.end(), 3);
    std::cout << "نتيجة خاطئة: " << wrong << '\n';

    // ✅ رتّب أولًا ثم ابحث
    std::sort(v.begin(), v.end());
    bool correct = std::binary_search(v.begin(), v.end(), 3);
    std::cout << "نتيجة صحيحة: " << correct << '\n'; // 1 (true)

    // ✅ أو استخدم find إذا لم تُرد ترتيب النطاق
    auto it = std::find(v.begin(), v.end(), 3);
    // find يعمل على أي ترتيب لكنه O(n) بدل O(log n)

    return 0;
}
